17: package org.apache.kafka.clients.producer;
18: 
19: import org.apache.kafka.common.header.Header;
20: import org.apache.kafka.common.header.Headers;
21: import org.apache.kafka.common.header.internals.RecordHeaders;
22: 
23: import java.util.Objects;
24: 
25: /**
26:  * A key/value pair to be sent to Kafka. This consists of a topic name to which the record is being sent, an optional
27:  * partition number, and an optional key and value.
28:  * <p>
29:  * If a valid partition number is specified that partition will be used when sending the record. If no partition is
30:  * specified but a key is present a partition will be chosen using a hash of the key. If neither key nor partition is
31:  * present a partition will be assigned in a round-robin fashion. Note that partition numbers are 0-indexed.
32:  * <p>
33:  * The record also has an associated timestamp. If the user did not provide a timestamp, the producer will stamp the
34:  * record with its current time. The timestamp eventually used by Kafka depends on the timestamp type configured for
35:  * the topic.
36:  * <li>
37:  * If the topic is configured to use {@link org.apache.kafka.common.record.TimestampType#CREATE_TIME CreateTime},
38:  * the timestamp in the producer record will be used by the broker.
39:  * </li>
40:  * <li>
41:  * If the topic is configured to use {@link org.apache.kafka.common.record.TimestampType#LOG_APPEND_TIME LogAppendTime},
42:  * the timestamp in the producer record will be overwritten by the broker with the broker local time when it appends the
43:  * message to its log.
44:  * </li>
45:  * <p>
46:  * In either of the cases above, the timestamp that has actually been used will be returned to user in
47:  * {@link RecordMetadata}
48:  */
49: public class ProducerRecord<K, V> {
50: 
51:     private final String topic;
52:     private final Integer partition;
53:     private final Headers headers;
54:     private final K key;
55:     private final V value;
56:     private final Long timestamp;
57: 
58:     /**
59:      * Creates a record with a specified timestamp to be sent to a specified topic and partition
60:      * 
61:      * @param topic The topic the record will be appended to
62:      * @param partition The partition to which the record should be sent
63:      * @param timestamp The timestamp of the record, in milliseconds since epoch. If null, the producer will assign
64:      *                  the timestamp using System.currentTimeMillis().
65:      * @param key The key that will be included in the record
66:      * @param value The record contents
67:      * @param headers the headers that will be included in the record
68:      */
69:     public ProducerRecord(String topic, Integer partition, Long timestamp, K key, V value, Iterable<Header> headers) {
70:         if (topic == null)
71:             throw new IllegalArgumentException("Topic cannot be null.");
72:         if (timestamp != null && timestamp < 0)
73:             throw new IllegalArgumentException(
74:                     String.format("Invalid timestamp: %d. Timestamp should always be non-negative or null.", timestamp));
75:         if (partition != null && partition < 0)
76:             throw new IllegalArgumentException(
77:                     String.format("Invalid partition: %d. Partition number should always be non-negative or null.", partition));
78:         this.topic = topic;
79:         this.partition = partition;
80:         this.key = key;
81:         this.value = value;
82:         this.timestamp = timestamp;
83:         this.headers = new RecordHeaders(headers);
84:     }
85: 
86:     /**
87:      * Creates a record with a specified timestamp to be sent to a specified topic and partition
88:      *
89:      * @param topic The topic the record will be appended to
90:      * @param partition The partition to which the record should be sent
91:      * @param timestamp The timestamp of the record, in milliseconds since epoch. If null, the producer will assign the
92:      *                  timestamp using System.currentTimeMillis().
93:      * @param key The key that will be included in the record
94:      * @param value The record contents
95:      */
96:     public ProducerRecord(String topic, Integer partition, Long timestamp, K key, V value) {
97:         this(topic, partition, timestamp, key, value, null);
98:     }
99: 
100:     /**
101:      * Creates a record to be sent to a specified topic and partition
102:      *
103:      * @param topic The topic the record will be appended to
104:      * @param partition The partition to which the record should be sent
105:      * @param key The key that will be included in the record
106:      * @param value The record contents
107:      * @param headers The headers that will be included in the record
108:      */
109:     public ProducerRecord(String topic, Integer partition, K key, V value, Iterable<Header> headers) {
110:         this(topic, partition, null, key, value, headers);
111:     }
112:     
113:     /**
114:      * Creates a record to be sent to a specified topic and partition
115:      *
116:      * @param topic The topic the record will be appended to
117:      * @param partition The partition to which the record should be sent
118:      * @param key The key that will be included in the record
119:      * @param value The record contents
120:      */
121:     public ProducerRecord(String topic, Integer partition, K key, V value) {
122:         this(topic, partition, null, key, value, null);
123:     }
124:     
125:     /**
126:      * Create a record to be sent to Kafka
127:      * 
128:      * @param topic The topic the record will be appended to
129:      * @param key The key that will be included in the record
130:      * @param value The record contents
131:      */
132:     public ProducerRecord(String topic, K key, V value) {
133:         this(topic, null, null, key, value, null);
134:     }
135:     
136:     /**
137:      * Create a record with no key
138:      * 
139:      * @param topic The topic this record should be sent to
140:      * @param value The record contents
141:      */
142:     public ProducerRecord(String topic, V value) {
143:         this(topic, null, null, null, value, null);
144:     }
145: 
146:     /**
147:      * @return The topic this record is being sent to
148:      */
149:     public String topic() {
150:         return topic;
151:     }
152: 
153:     /**
154:      * @return The headers
155:      */
156:     public Headers headers() {
157:         return headers;
158:     }
159: 
160:     /**
161:      * @return The key (or null if no key is specified)
162:      */
163:     public K key() {
164:         return key;
165:     }
166: 
167:     /**
168:      * @return The value
169:      */
170:     public V value() {
171:         return value;
172:     }
173: 
174:     /**
175:      * @return The timestamp, which is in milliseconds since epoch.
176:      */
177:     public Long timestamp() {
178:         return timestamp;
179:     }
180: 
181:     /**
182:      * @return The partition to which the record will be sent (or null if no partition was specified)
183:      */
184:     public Integer partition() {
185:         return partition;
186:     }
187: 
188:     @Override
189:     public String toString() {
190:         String headers = this.headers == null ? "null" : this.headers.toString();
191:         String key = this.key == null ? "null" : this.key.toString();
192:         String value = this.value == null ? "null" : this.value.toString();
193:         String timestamp = this.timestamp == null ? "null" : this.timestamp.toString();
194:         return "ProducerRecord(topic=" + topic + ", partition=" + partition + ", headers=" + headers + ", key=" + key + ", value=" + value +
195:             ", timestamp=" + timestamp + ")";
196:     }
197: 
198:     @Override
199:     public boolean equals(Object o) {
200:         if (this == o)
201:             return true;
202:         else if (!(o instanceof ProducerRecord))
203:             return false;
204: 
205:         ProducerRecord<?, ?> that = (ProducerRecord<?, ?>) o;
206: 
207:         return Objects.equals(key, that.key) &&
208:             Objects.equals(partition, that.partition) &&
209:             Objects.equals(topic, that.topic) &&
210:             Objects.equals(headers, that.headers) &&
211:             Objects.equals(value, that.value) &&
212:             Objects.equals(timestamp, that.timestamp);
213:     }
214: 
215:     @Override
216:     public int hashCode() {
217:         int result = topic != null ? topic.hashCode() : 0;
218:         result = 31 * result + (partition != null ? partition.hashCode() : 0);
219:         result = 31 * result + (headers != null ? headers.hashCode() : 0);
220:         result = 31 * result + (key != null ? key.hashCode() : 0);
221:         result = 31 * result + (value != null ? value.hashCode() : 0);
222:         result = 31 * result + (timestamp != null ? timestamp.hashCode() : 0);
223:         return result;
224:     }
225: }
