52: import static org.apache.kafka.common.record.RecordBatch.MAGIC_VALUE_V2;
53: import static org.apache.kafka.common.record.RecordBatch.NO_TIMESTAMP;
54: 
55: /**
56:  * A batch of records that is or will be sent.
57:  *
58:  * This class is not thread safe and external synchronization must be used when modifying it
59:  */
60: public final class ProducerBatch {
61: 
62:     private static final Logger log = LoggerFactory.getLogger(ProducerBatch.class);
63: 
64:     private enum FinalState { ABORTED, FAILED, SUCCEEDED }
65: 
66:     final long createdMs;
67:     final TopicPartition topicPartition;
68:     final ProduceRequestResult produceFuture;
69: 
70:     private final List<Thunk> thunks = new ArrayList<>();
71:     private final MemoryRecordsBuilder recordsBuilder;
72:     private final AtomicInteger attempts = new AtomicInteger(0);
73:     private final boolean isSplitBatch;
74:     private final AtomicReference<FinalState> finalState = new AtomicReference<>(null);
75: 
76:     int recordCount;
77:     int maxRecordSize;
78:     private long lastAttemptMs;
79:     private long lastAppendTime;
80:     private long drainedMs;
81:     private boolean retry;
82:     private boolean reopened;
83: 
84:     // Tracks the current-leader's epoch to which this batch would be sent, in the current to produce the batch.
85:     private OptionalInt currentLeaderEpoch;
86:     // Tracks the attempt in which leader was changed to currentLeaderEpoch for the 1st time.
87:     private int attemptsWhenLeaderLastChanged;
88: 
89:     public ProducerBatch(TopicPartition tp, MemoryRecordsBuilder recordsBuilder, long createdMs) {
90:         this(tp, recordsBuilder, createdMs, false);
91:     }
92: 
93:     public ProducerBatch(TopicPartition tp, MemoryRecordsBuilder recordsBuilder, long createdMs, boolean isSplitBatch) {
94:         this.createdMs = createdMs;
95:         this.lastAttemptMs = createdMs;
96:         this.recordsBuilder = recordsBuilder;
97:         this.topicPartition = tp;
98:         this.lastAppendTime = createdMs;
99:         this.produceFuture = new ProduceRequestResult(topicPartition);
100:         this.retry = false;
101:         this.isSplitBatch = isSplitBatch;
102:         float compressionRatioEstimation = CompressionRatioEstimator.estimation(topicPartition.topic(),
103:                                                                                 recordsBuilder.compression().type());
104:         this.currentLeaderEpoch = OptionalInt.empty();
105:         this.attemptsWhenLeaderLastChanged = 0;
106:         recordsBuilder.setEstimatedCompressionRatio(compressionRatioEstimation);
107:     }
108: 
109:     /**
110:      * It will update the leader to which this batch will be produced for the ongoing attempt, if a newer leader is known.
111:      * @param latestLeaderEpoch latest leader's epoch.
112:      */
113:     void maybeUpdateLeaderEpoch(OptionalInt latestLeaderEpoch) {
114:         if (latestLeaderEpoch.isPresent()
115:             && (currentLeaderEpoch.isEmpty() || currentLeaderEpoch.getAsInt() < latestLeaderEpoch.getAsInt())) {
116:             log.trace("For {}, leader will be updated, currentLeaderEpoch: {}, attemptsWhenLeaderLastChanged:{}, latestLeaderEpoch: {}, current attempt: {}",
117:                 this, currentLeaderEpoch, attemptsWhenLeaderLastChanged, latestLeaderEpoch, attempts);
118:             attemptsWhenLeaderLastChanged = attempts();
119:             currentLeaderEpoch = latestLeaderEpoch;
120:         } else {
121:             log.trace("For {}, leader wasn't updated, currentLeaderEpoch: {}, attemptsWhenLeaderLastChanged:{}, latestLeaderEpoch: {}, current attempt: {}",
122:                 this, currentLeaderEpoch, attemptsWhenLeaderLastChanged, latestLeaderEpoch, attempts);
123:         }
124:     }
125: 
126:     /**
127:      * It will return true, for a when batch is being retried, it will be retried to a newer leader.
128:      */
129: 
130:     boolean hasLeaderChangedForTheOngoingRetry() {
131:         int attempts = attempts();
132:         boolean isRetry = attempts >= 1;
133:         if (!isRetry)
134:             return false;
135:         return attempts == attemptsWhenLeaderLastChanged;
136:     }
137: 
138: 
139:     /**
140:      * Append the record to the current record set and return the relative offset within that record set
141:      *
142:      * @return The RecordSend corresponding to this record or null if there isn't sufficient room.
143:      */
144:     public FutureRecordMetadata tryAppend(long timestamp, byte[] key, byte[] value, Header[] headers, Callback callback, long now) {
145:         if (!recordsBuilder.hasRoomFor(timestamp, key, value, headers)) {
146:             return null;
147:         } else {
148:             this.recordsBuilder.append(timestamp, key, value, headers);
149:             this.maxRecordSize = Math.max(this.maxRecordSize, AbstractRecords.estimateSizeInBytesUpperBound(magic(),
150:                     recordsBuilder.compression().type(), key, value, headers));
151:             this.lastAppendTime = now;
152:             FutureRecordMetadata future = new FutureRecordMetadata(this.produceFuture, this.recordCount,
153:                                                                    timestamp,
154:                                                                    key == null ? -1 : key.length,
155:                                                                    value == null ? -1 : value.length,
156:                                                                    Time.SYSTEM);
157:             // we have to keep every future returned to the users in case the batch needs to be
158:             // split to several new batches and resent.
159:             thunks.add(new Thunk(callback, future));
160:             this.recordCount++;
161:             return future;
162:         }
163:     }
164: 
165:     /**
166:      * This method is only used by {@link #split(int)} when splitting a large batch to smaller ones.
167:      * @return true if the record has been successfully appended, false otherwise.
168:      */
169:     private boolean tryAppendForSplit(long timestamp, ByteBuffer key, ByteBuffer value, Header[] headers, Thunk thunk) {
170:         if (!recordsBuilder.hasRoomFor(timestamp, key, value, headers)) {
171:             return false;
172:         } else {
173:             // No need to get the CRC.
174:             this.recordsBuilder.append(timestamp, key, value, headers);
175:             this.maxRecordSize = Math.max(this.maxRecordSize, AbstractRecords.estimateSizeInBytesUpperBound(magic(),
176:                     recordsBuilder.compression().type(), key, value, headers));
177:             FutureRecordMetadata future = new FutureRecordMetadata(this.produceFuture, this.recordCount,
178:                                                                    timestamp,
179:                                                                    key == null ? -1 : key.remaining(),
180:                                                                    value == null ? -1 : value.remaining(),
181:                                                                    Time.SYSTEM);
182:             // Chain the future to the original thunk.
183:             thunk.future.chain(future);
184:             this.thunks.add(thunk);
185:             this.recordCount++;
186:             return true;
187:         }
188:     }
189: 
190:     /**
191:      * Abort the batch and complete the future and callbacks.
192:      *
193:      * @param exception The exception to use to complete the future and awaiting callbacks.
194:      */
195:     public void abort(RuntimeException exception) {
196:         if (!finalState.compareAndSet(null, FinalState.ABORTED))
197:             throw new IllegalStateException("Batch has already been completed in final state " + finalState.get());
198: 
199:         log.trace("Aborting batch for partition {}", topicPartition, exception);
200:         completeFutureAndFireCallbacks(ProduceResponse.INVALID_OFFSET, RecordBatch.NO_TIMESTAMP, index -> exception);
201:     }
202: 
203:     /**
204:      * Check if the batch has been completed (either successfully or exceptionally).
205:      * @return `true` if the batch has been completed, `false` otherwise.
206:      */
207:     public boolean isDone() {
208:         return finalState() != null;
209:     }
210: 
211:     /**
212:      * Complete the batch successfully.
213:      * @param baseOffset The base offset of the messages assigned by the server
214:      * @param logAppendTime The log append time or -1 if CreateTime is being used
215:      * @return true if the batch was completed as a result of this call, and false
216:      *   if it had been completed previously
217:      */
218:     public boolean complete(long baseOffset, long logAppendTime) {
219:         return done(baseOffset, logAppendTime, null, null);
220:     }
221: 
222:     /**
223:      * Complete the batch exceptionally. The provided top-level exception will be used
224:      * for each record future contained in the batch.
225:      *
226:      * @param topLevelException top-level partition error
227:      * @param recordExceptions Record exception function mapping batchIndex to the respective record exception
228:      * @return true if the batch was completed as a result of this call, and false
229:      *   if it had been completed previously
230:      */
231:     public boolean completeExceptionally(
232:         RuntimeException topLevelException,
233:         Function<Integer, RuntimeException> recordExceptions
234:     ) {
235:         Objects.requireNonNull(topLevelException);
236:         Objects.requireNonNull(recordExceptions);
237:         return done(ProduceResponse.INVALID_OFFSET, RecordBatch.NO_TIMESTAMP, topLevelException, recordExceptions);
238:     }
239: 
240:     /**
241:      * Finalize the state of a batch. Final state, once set, is immutable. This function may be called
242:      * once or twice on a batch. It may be called twice if
243:      * 1. An inflight batch expires before a response from the broker is received. The batch's final
244:      * state is set to FAILED. But it could succeed on the broker and second time around batch.done() may
245:      * try to set SUCCEEDED final state.
246:      * 2. If a transaction abortion happens or if the producer is closed forcefully, the final state is
247:      * ABORTED but again it could succeed if broker responds with a success.
248:      *
249:      * Attempted transitions from [FAILED | ABORTED] --> SUCCEEDED are logged.
250:      * Attempted transitions from one failure state to the same or a different failed state are ignored.
251:      * Attempted transitions from SUCCEEDED to the same or a failed state throw an exception.
252:      *
253:      * @param baseOffset The base offset of the messages assigned by the server
254:      * @param logAppendTime The log append time or -1 if CreateTime is being used
255:      * @param topLevelException The exception that occurred (or null if the request was successful)
256:      * @param recordExceptions Record exception function mapping batchIndex to the respective record exception
257:      * @return true if the batch was completed successfully and false if the batch was previously aborted
258:      */
259:     private boolean done(
260:         long baseOffset,
261:         long logAppendTime,
262:         RuntimeException topLevelException,
263:         Function<Integer, RuntimeException> recordExceptions
264:     ) {
265:         final FinalState tryFinalState = (topLevelException == null) ? FinalState.SUCCEEDED : FinalState.FAILED;
266:         if (tryFinalState == FinalState.SUCCEEDED) {
267:             log.trace("Successfully produced messages to {} with base offset {}.", topicPartition, baseOffset);
268:         } else {
269:             log.trace("Failed to produce messages to {} with base offset {}.", topicPartition, baseOffset, topLevelException);
270:         }
271: 
272:         if (this.finalState.compareAndSet(null, tryFinalState)) {
273:             completeFutureAndFireCallbacks(baseOffset, logAppendTime, recordExceptions);
274:             return true;
275:         }
276: 
277:         if (this.finalState.get() != FinalState.SUCCEEDED) {
278:             if (tryFinalState == FinalState.SUCCEEDED) {
279:                 // Log if a previously unsuccessful batch succeeded later on.
280:                 log.debug("ProduceResponse returned {} for {} after batch with base offset {} had already been {}.",
281:                     tryFinalState, topicPartition, baseOffset, this.finalState.get());
282:             } else {
283:                 // FAILED --> FAILED and ABORTED --> FAILED transitions are ignored.
284:                 log.debug("Ignored state transition {} -> {} for {} batch with base offset {}",
285:                     this.finalState.get(), tryFinalState, topicPartition, baseOffset);
286:             }
287:         } else {
288:             // A SUCCESSFUL batch must not attempt another state change.
289:             throw new IllegalStateException("A " + this.finalState.get() + " batch must not attempt another state change to " + tryFinalState);
290:         }
291:         return false;
292:     }
293: 
294:     private void completeFutureAndFireCallbacks(
295:         long baseOffset,
296:         long logAppendTime,
297:         Function<Integer, RuntimeException> recordExceptions
298:     ) {
299:         // Set the future before invoking the callbacks as we rely on its state for the `onCompletion` call
300:         produceFuture.set(baseOffset, logAppendTime, recordExceptions);
301: 
302:         // execute callbacks
303:         for (int i = 0; i < thunks.size(); i++) {
304:             try {
305:                 Thunk thunk = thunks.get(i);
306:                 if (thunk.callback != null) {
307:                     if (recordExceptions == null) {
308:                         RecordMetadata metadata = thunk.future.value();
309:                         thunk.callback.onCompletion(metadata, null);
310:                     } else {
311:                         RuntimeException exception = recordExceptions.apply(i);
312:                         thunk.callback.onCompletion(null, exception);
313:                     }
314:                 }
315:             } catch (Exception e) {
316:                 log.error("Error executing user-provided callback on message for topic-partition '{}'", topicPartition, e);
317:             }
318:         }
319: 
320:         produceFuture.done();
321:     }
322: 
323:     public Deque<ProducerBatch> split(int splitBatchSize) {
324:         RecordBatch recordBatch = validateAndGetRecordBatch();
325:         Deque<ProducerBatch> batches = splitRecordsIntoBatches(recordBatch, splitBatchSize);
326:         finalizeSplitBatches(batches);
327:         return batches;
328:     }
329: 
330:     private RecordBatch validateAndGetRecordBatch() {
331:         MemoryRecords memoryRecords = recordsBuilder.build();
332:         Iterator<MutableRecordBatch> recordBatchIter = memoryRecords.batches().iterator();
333: 
334:         if (!recordBatchIter.hasNext())
335:             throw new IllegalStateException("Cannot split an empty producer batch.");
336: 
337:         RecordBatch recordBatch = recordBatchIter.next();
338:         if (recordBatch.magic() < MAGIC_VALUE_V2 && !recordBatch.isCompressed())
339:             throw new IllegalArgumentException("Batch splitting cannot be used with non-compressed messages " +
340:                     "with version v0 and v1");
341: 
342:         if (recordBatchIter.hasNext())
343:             throw new IllegalArgumentException("A producer batch should only have one record batch.");
344: 
345:         return recordBatch;
346:     }
347: 
348:     private Deque<ProducerBatch> splitRecordsIntoBatches(RecordBatch recordBatch, int splitBatchSize) {
349:         Deque<ProducerBatch> batches = new ArrayDeque<>();
350:         Iterator<Thunk> thunkIter = thunks.iterator();
351:         // We always allocate batch size because we are already splitting a big batch.
352:         // And we also Retain the create time of the original batch.
353:         ProducerBatch batch = null;
354: 
355:         for (Record record : recordBatch) {
356:             assert thunkIter.hasNext();
357:             Thunk thunk = thunkIter.next();
358:             if (batch == null)
359:                 batch = createBatchOffAccumulatorForRecord(record, splitBatchSize);
360: 
361:             // A newly created batch can always host the first message.
362:             if (!batch.tryAppendForSplit(record.timestamp(), record.key(), record.value(), record.headers(), thunk)) {
363:                 batches.add(batch);
364:                 batch.closeForRecordAppends();
365:                 batch = createBatchOffAccumulatorForRecord(record, splitBatchSize);
366:                 batch.tryAppendForSplit(record.timestamp(), record.key(), record.value(), record.headers(), thunk);
367:             }
368:         }
369: 
370:         // Close the last batch and add it to the batch list after split.
371:         if (batch != null) {
372:             batches.add(batch);
373:             batch.closeForRecordAppends();
374:         }
375: 
376:         return batches;
377:     }
378: 
379:     private void finalizeSplitBatches(Deque<ProducerBatch> batches) {
380:         // Chain all split batch ProduceRequestResults to the original batch's produceFuture
381:         // Ensures the original batch's future doesn't complete until all split batches complete
382:         for (ProducerBatch splitBatch : batches) {
383:             produceFuture.addDependent(splitBatch.produceFuture);
384:         }
385: 
386:         produceFuture.set(ProduceResponse.INVALID_OFFSET, NO_TIMESTAMP, index -> new RecordBatchTooLargeException());
387:         produceFuture.done();
388: 
389:         assignProducerStateToBatches(batches);
390:     }
391: 
392:     private void assignProducerStateToBatches(Deque<ProducerBatch> batches) {
393:         if (hasSequence()) {
394:             int sequence = baseSequence();
395:             ProducerIdAndEpoch producerIdAndEpoch = new ProducerIdAndEpoch(producerId(), producerEpoch());
396:             for (ProducerBatch newBatch : batches) {
397:                 newBatch.setProducerState(producerIdAndEpoch, sequence, isTransactional());
398:                 sequence += newBatch.recordCount;
399:             }
400:         }
401:     }
402: 
403:     private ProducerBatch createBatchOffAccumulatorForRecord(Record record, int batchSize) {
404:         int initialSize = Math.max(AbstractRecords.estimateSizeInBytesUpperBound(magic(),
405:                 recordsBuilder.compression().type(), record.key(), record.value(), record.headers()), batchSize);
406:         ByteBuffer buffer = ByteBuffer.allocate(initialSize);
407: 
408:         // Note that we intentionally do not set producer state (producerId, epoch, sequence, and isTransactional)
409:         // for the newly created batch. This will be set when the batch is dequeued for sending (which is consistent
410:         // with how normal batches are handled).
411:         MemoryRecordsBuilder builder = MemoryRecords.builder(buffer, magic(), recordsBuilder.compression(),
412:                 TimestampType.CREATE_TIME, 0L);
413:         return new ProducerBatch(topicPartition, builder, this.createdMs, true);
414:     }
